def token_jaccard(a: str, b: str) -> float:
    A = set(a.replace(".", " ").casefold().split())
    B = set(b.replace(".", " ").casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)

