import time

def fetch_with_retry(fn, max_attempts=3):
    last = None
    for attempt in range(1, max_attempts + 1):
        try:
            return fn(attempt)
        except TimeoutError as e:
            last = e
            time.sleep(0.01 * attempt)  # backoff demo
        except ValueError:
            raise  # no retry
    raise last

