@dataclass
class ClientRecord:
    client_id: str
    document_id: str
    full_name: str
    emails: list[str] = field(default_factory=list)

    def __post_init__(self) -> None:
        if not self.client_id or not self.document_id.strip():
            raise ValueError("client_id/document_id invÃĄlidos")

